from typing import Any, Dict, List, Optional

# --- Type Definitions ---
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# --- Constants ---
GRID_SIZE = 3
P0, P1, TERMINAL = 0, 1, -4
MARKS = {P0: 'x', P1: 'o'}

# --- Helper Functions ---

def _check_winner(board: List[List[str]]) -> Optional[str]:
    """Checks rows, columns, and diagonals for a winning mark."""
    # Generate all lines: 3 rows, 3 cols, 2 diagonals
    lines = (
        board + 
        [[board[r][c] for r in range(GRID_SIZE)] for c in range(GRID_SIZE)] +
        [[board[i][i] for i in range(GRID_SIZE)], [board[i][GRID_SIZE-1-i] for i in range(GRID_SIZE)]]
    )
    for line in lines:
        if line[0] != '' and all(cell == line[0] for cell in line):
            return line[0]
    return None

def _is_full(board: List[List[str]]) -> bool:
    """Returns True if no empty spaces remain."""
    return all(cell != '' for row in board for cell in row)

# --- Game Functions ---

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        'board': [['' for _ in range(GRID_SIZE)] for _ in range(GRID_SIZE)],
        'current_player': P0,
        'status': 'ongoing' # ongoing, x_won, o_won, draw
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    # Parse action string 'mark(row,col)'
    content = action.split('(')[1].strip(')')
    r, c = map(int, content.split(','))

    # Create new board to preserve immutability
    new_board = [row[:] for row in state['board']]
    curr_p = state['current_player']
    new_board[r][c] = MARKS[curr_p]

    new_state = {
        'board': new_board,
        'current_player': 1 - curr_p, # Switch turns
        'status': 'ongoing'
    }

    # Check game over conditions
    winner = _check_winner(new_board)
    if winner:
        new_state['status'] = f'{winner}_won'
        new_state['current_player'] = TERMINAL
    elif _is_full(new_board):
        new_state['status'] = 'draw'
        new_state['current_player'] = TERMINAL

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, with -1 for chance and -4 for terminal."""
    return state['current_player']

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0"
    if player_id == P1: return "Player 1"
    return "Terminal"

def get_rewards(state: State) -> list[float]:
    """Returns the rewards per player from their last action."""
    status = state['status']
    if status == 'x_won':
        return [1.0, -1.0]
    elif status == 'o_won':
        return [-1.0, 1.0]
    return [0.0, 0.0] # Draw or ongoing

def get_legal_actions(state: State) -> list[Action]:
    """Returns legal actions that can be taken in current state."""
    if state['current_player'] == TERMINAL:
        return []

    mark = MARKS[state['current_player']]
    actions = []
    for r in range(GRID_SIZE):
        for c in range(GRID_SIZE):
            if state['board'][r][c] == '':
                actions.append(f"{mark}({r},{c})")
    return actions

def get_observations(state: State) -> list[PlayerObservation]:
    """Returns the observation for player."""
    # Tic-Tac-Toe is a perfect information game; both see the full state.
    obs = {'board': state['board'], 'status': state['status']}
    return [obs, obs]

from typing import Any, Dict, List, Optional, Tuple
import random

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
ACTIONS = ["H", "T"]  # Heads, Tails

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        "p0_choice": None,  # P0's secret choice
        "p1_choice": None,  # P1's secret choice
        "current_player": P0,
        "is_terminal": False
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = state.copy()

    if state["current_player"] == P0:
        new_state["p0_choice"] = action
        new_state["current_player"] = P1
    elif state["current_player"] == P1:
        new_state["p1_choice"] = action
        new_state["current_player"] = TERMINAL
        new_state["is_terminal"] = True

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0 (Matcher)"
    if player_id == P1: return "Player 1 (Mismatcher)"
    return "Terminal"

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state["is_terminal"]:
        return [0.0, 0.0]

    p0_choice = state["p0_choice"]
    p1_choice = state["p1_choice"]

    # P0 wins if choices match, P1 wins if they differ
    if p0_choice == p1_choice:
        return [1.0, -1.0]  # Match: P0 wins
    else:
        return [-1.0, 1.0]  # Mismatch: P1 wins

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state["is_terminal"]:
        return []
    return ACTIONS.copy()

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Players only see their own choice until terminal."""
    if state["is_terminal"]:
        # At terminal, both see the full outcome
        return [
            {"my_choice": state["p0_choice"], "opponent_choice": state["p1_choice"]},
            {"my_choice": state["p1_choice"], "opponent_choice": state["p0_choice"]}
        ]

    # During play, players only see their own committed choice (if any)
    return [
        {"my_choice": state["p0_choice"]},
        {"my_choice": state["p1_choice"]}
    ]

def resample_history(obs_action_history: List[Tuple[PlayerObservation, Optional[Action]]], player_id: int) -> List[Action]:
    """Stochastically sample a history consistent with player_id's view."""
    if not obs_action_history:
        return []

    last_obs, last_action = obs_action_history[-1]
    my_choice = last_obs.get("my_choice")

    # Sample opponent's choice uniformly (we don't know it)
    opponent_choice = random.choice(ACTIONS)

    if player_id == P0:
        history = []
        if my_choice is not None:
            history.append(my_choice)
        if "opponent_choice" in last_obs:
            history.append(last_obs["opponent_choice"])
        elif my_choice is not None:
            # P1 has acted but we haven't seen it yet
            history.append(opponent_choice)
    else:
        history = []
        # P0 acted first
        if "opponent_choice" in last_obs:
            history.append(last_obs["opponent_choice"])
        else:
            history.append(opponent_choice)
        if my_choice is not None:
            history.append(my_choice)

    if last_action is not None and (not history or history[-1] != last_action):
        history.append(last_action)

    return history

from typing import Any, Dict, List, Optional, Tuple
import random

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
ACTIONS = ["C", "D"]  # Cooperate, Defect

# Payoff matrix: PAYOFFS[p0_action][p1_action] = (p0_reward, p1_reward)
PAYOFFS = {
    "C": {"C": (3.0, 3.0), "D": (0.0, 5.0)},
    "D": {"C": (5.0, 0.0), "D": (1.0, 1.0)}
}

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        "p0_choice": None,
        "p1_choice": None,
        "current_player": P0,
        "is_terminal": False
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = state.copy()

    if state["current_player"] == P0:
        new_state["p0_choice"] = action
        new_state["current_player"] = P1
    elif state["current_player"] == P1:
        new_state["p1_choice"] = action
        new_state["current_player"] = TERMINAL
        new_state["is_terminal"] = True

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0"
    if player_id == P1: return "Player 1"
    return "Terminal"

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state["is_terminal"]:
        return [0.0, 0.0]

    p0_choice = state["p0_choice"]
    p1_choice = state["p1_choice"]
    p0_reward, p1_reward = PAYOFFS[p0_choice][p1_choice]
    # Normalize to zero-sum by subtracting mean
    mean_reward = (p0_reward + p1_reward) / 2
    return [p0_reward - mean_reward, p1_reward - mean_reward]

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state["is_terminal"]:
        return []
    return ACTIONS.copy()

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Players only see their own choice until terminal."""
    if state["is_terminal"]:
        return [
            {"my_choice": state["p0_choice"], "opponent_choice": state["p1_choice"]},
            {"my_choice": state["p1_choice"], "opponent_choice": state["p0_choice"]}
        ]

    return [
        {"my_choice": state["p0_choice"]},
        {"my_choice": state["p1_choice"]}
    ]

def resample_history(obs_action_history: List[Tuple[PlayerObservation, Optional[Action]]], player_id: int) -> List[Action]:
    """Stochastically sample a history consistent with player_id's view."""
    if not obs_action_history:
        return []

    last_obs, last_action = obs_action_history[-1]
    my_choice = last_obs.get("my_choice")

    # Sample opponent's choice uniformly
    opponent_choice = random.choice(ACTIONS)

    if player_id == P0:
        history = []
        if my_choice is not None:
            history.append(my_choice)
        if "opponent_choice" in last_obs:
            history.append(last_obs["opponent_choice"])
        elif my_choice is not None:
            history.append(opponent_choice)
    else:
        history = []
        if "opponent_choice" in last_obs:
            history.append(last_obs["opponent_choice"])
        else:
            history.append(opponent_choice)
        if my_choice is not None:
            history.append(my_choice)

    if last_action is not None and (not history or history[-1] != last_action):
        history.append(last_action)

    return history

from typing import Any, Dict, List, Optional, Tuple
import random

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, CHANCE, TERMINAL = 0, 1, -1, -4
WIN_SCORE = 100
DIE_SIDES = 6

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        "scores": [0, 0],          # Permanent scores for each player
        "turn_total": 0,           # Points accumulated this turn
        "current_player": P0,
        "waiting_for_chance": False,  # True if we need a die roll
        "is_terminal": False,
        "winner": None
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = {
        "scores": state["scores"].copy(),
        "turn_total": state["turn_total"],
        "current_player": state["current_player"],
        "waiting_for_chance": state["waiting_for_chance"],
        "is_terminal": state["is_terminal"],
        "winner": state["winner"]
    }

    if state["current_player"] == CHANCE:
        # Die roll outcome
        die_value = int(action)
        current = state["waiting_for_chance"]  # Player who rolled

        if die_value == 1:
            # Pigged out - lose turn total, switch players
            new_state["turn_total"] = 0
            new_state["current_player"] = 1 - current
            new_state["waiting_for_chance"] = False
        else:
            # Add to turn total, continue turn
            new_state["turn_total"] = state["turn_total"] + die_value
            new_state["current_player"] = current
            new_state["waiting_for_chance"] = False

    elif action == "roll":
        # Player chooses to roll
        new_state["waiting_for_chance"] = state["current_player"]
        new_state["current_player"] = CHANCE

    elif action == "hold":
        # Player banks points
        current = state["current_player"]
        new_score = state["scores"][current] + state["turn_total"]
        new_state["scores"][current] = new_score
        new_state["turn_total"] = 0

        if new_score >= WIN_SCORE:
            new_state["is_terminal"] = True
            new_state["winner"] = current
            new_state["current_player"] = TERMINAL
        else:
            new_state["current_player"] = 1 - current

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, with -1 for chance and -4 for terminal."""
    if state["is_terminal"]:
        return TERMINAL
    if state["current_player"] == CHANCE:
        return CHANCE
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    names = {P0: "Player 0", P1: "Player 1", CHANCE: "Chance", TERMINAL: "Terminal"}
    return names.get(player_id, "Unknown")

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state["is_terminal"]:
        return [0.0, 0.0]

    if state["winner"] == P0:
        return [1.0, -1.0]
    else:
        return [-1.0, 1.0]

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state["is_terminal"]:
        return []

    if state["current_player"] == CHANCE:
        return [str(i) for i in range(1, DIE_SIDES + 1)]

    # Player actions
    actions = ["roll"]

    # Can only hold if we have points to bank
    if state["turn_total"] > 0:
        actions.append("hold")

    return actions

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Pig is perfect information."""
    obs = {
        "scores": state["scores"],
        "turn_total": state["turn_total"],
        "current_player": state["current_player"]
    }
    return [obs, obs]

from typing import Any, Dict, List, Set, Tuple

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
NUM_ROWS = 3  # Dots in each column (creates NUM_ROWS-1 box rows)
NUM_COLS = 3  # Dots in each row (creates NUM_COLS-1 box columns)

def _get_all_lines() -> List[Action]:
    """Get all possible line actions."""
    lines = []
    # Horizontal lines: between (r, c) and (r, c+1)
    for r in range(NUM_ROWS):
        for c in range(NUM_COLS - 1):
            lines.append(f"h_{r}_{c}")
    # Vertical lines: between (r, c) and (r+1, c)
    for r in range(NUM_ROWS - 1):
        for c in range(NUM_COLS):
            lines.append(f"v_{r}_{c}")
    return lines

def _check_box_completed(drawn_lines: Set[str], box_r: int, box_c: int) -> bool:
    """Check if a box at position (box_r, box_c) is completed.
    Box (r, c) has corners at dots (r,c), (r,c+1), (r+1,c), (r+1,c+1).
    """
    top = f"h_{box_r}_{box_c}"
    bottom = f"h_{box_r + 1}_{box_c}"
    left = f"v_{box_r}_{box_c}"
    right = f"v_{box_r}_{box_c + 1}"
    return all(line in drawn_lines for line in [top, bottom, left, right])

def _count_new_boxes(drawn_lines: Set[str], new_line: str) -> List[Tuple[int, int]]:
    """Return list of boxes completed by adding new_line."""
    new_drawn = drawn_lines | {new_line}
    completed = []

    # Check which boxes this line could complete
    parts = new_line.split("_")
    line_type = parts[0]
    r, c = int(parts[1]), int(parts[2])

    if line_type == "h":
        # Horizontal line at (r, c) to (r, c+1)
        # Could complete box above (r-1, c) or below (r, c)
        if r > 0:  # Box above
            if _check_box_completed(new_drawn, r - 1, c):
                completed.append((r - 1, c))
        if r < NUM_ROWS - 1:  # Box below
            if _check_box_completed(new_drawn, r, c):
                completed.append((r, c))
    else:
        # Vertical line at (r, c) to (r+1, c)
        # Could complete box to left (r, c-1) or right (r, c)
        if c > 0:  # Box to left
            if _check_box_completed(new_drawn, r, c - 1):
                completed.append((r, c - 1))
        if c < NUM_COLS - 1:  # Box to right
            if _check_box_completed(new_drawn, r, c):
                completed.append((r, c))

    return completed

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        "drawn_lines": set(),
        "box_owners": {},  # {(r, c): player_id}
        "scores": [0, 0],
        "current_player": P0,
        "is_terminal": False
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = {
        "drawn_lines": state["drawn_lines"].copy(),
        "box_owners": state["box_owners"].copy(),
        "scores": state["scores"].copy(),
        "current_player": state["current_player"],
        "is_terminal": False
    }

    current = state["current_player"]
    new_state["drawn_lines"].add(action)

    # Check for completed boxes
    new_boxes = _count_new_boxes(state["drawn_lines"], action)

    if new_boxes:
        # Player gets the boxes and another turn
        for box in new_boxes:
            new_state["box_owners"][box] = current
        new_state["scores"][current] += len(new_boxes)
        # Current player keeps their turn
    else:
        # Switch players
        new_state["current_player"] = 1 - current

    # Check if game is over (all lines drawn)
    total_boxes = (NUM_ROWS - 1) * (NUM_COLS - 1)
    if sum(new_state["scores"]) == total_boxes:
        new_state["is_terminal"] = True
        new_state["current_player"] = TERMINAL

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    names = {P0: "Player 0", P1: "Player 1", TERMINAL: "Terminal"}
    return names.get(player_id, "Unknown")

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state["is_terminal"]:
        return [0.0, 0.0]

    s0, s1 = state["scores"]
    if s0 > s1:
        return [1.0, -1.0]
    elif s1 > s0:
        return [-1.0, 1.0]
    else:
        return [0.0, 0.0]  # Draw

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state["is_terminal"]:
        return []

    all_lines = _get_all_lines()
    return [line for line in all_lines if line not in state["drawn_lines"]]

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Dots and Boxes is perfect information."""
    obs = {
        "drawn_lines": list(state["drawn_lines"]),
        "box_owners": dict(state["box_owners"]),
        "scores": state["scores"]
    }
    return [obs, obs]

from typing import Any, Dict, List, Optional, Set, Tuple
import copy

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
BOARD_SIZE = 9
STONES = {P0: 'B', P1: 'W'}  # Black, White
KOMI = 6.5  # Compensation for white

def _neighbors(r: int, c: int) -> List[Tuple[int, int]]:
    """Get orthogonal neighbors on board."""
    result = []
    for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
        nr, nc = r + dr, c + dc
        if 0 <= nr < BOARD_SIZE and 0 <= nc < BOARD_SIZE:
            result.append((nr, nc))
    return result

def _find_group(board: List[List[str]], r: int, c: int) -> Set[Tuple[int, int]]:
    """Find all stones connected to (r,c) of the same color."""
    color = board[r][c]
    if color == '':
        return set()

    group = set()
    stack = [(r, c)]

    while stack:
        cr, cc = stack.pop()
        if (cr, cc) in group:
            continue
        if board[cr][cc] != color:
            continue

        group.add((cr, cc))
        for nr, nc in _neighbors(cr, cc):
            if (nr, nc) not in group and board[nr][nc] == color:
                stack.append((nr, nc))

    return group

def _count_liberties(board: List[List[str]], group: Set[Tuple[int, int]]) -> int:
    """Count liberties (empty neighbors) of a group."""
    liberties = set()
    for r, c in group:
        for nr, nc in _neighbors(r, c):
            if board[nr][nc] == '':
                liberties.add((nr, nc))
    return len(liberties)

def _remove_group(board: List[List[str]], group: Set[Tuple[int, int]]) -> List[List[str]]:
    """Remove a group from the board."""
    new_board = [row[:] for row in board]
    for r, c in group:
        new_board[r][c] = ''
    return new_board

def _board_hash(board: List[List[str]]) -> str:
    """Create hash of board state for ko detection."""
    return ''.join(''.join(row) for row in board)

def _apply_move(board: List[List[str]], r: int, c: int, player: int) -> Optional[List[List[str]]]:
    """Apply a move and return new board, or None if illegal (suicide without capture)."""
    new_board = [row[:] for row in board]
    stone = STONES[player]
    opponent_stone = STONES[1 - player]

    new_board[r][c] = stone

    # First, check and remove any opponent groups with zero liberties
    captured = []
    for nr, nc in _neighbors(r, c):
        if new_board[nr][nc] == opponent_stone:
            group = _find_group(new_board, nr, nc)
            if _count_liberties(new_board, group) == 0:
                captured.extend(group)
                new_board = _remove_group(new_board, group)

    # Then, check if own group has liberties (suicide check)
    own_group = _find_group(new_board, r, c)
    if _count_liberties(new_board, own_group) == 0:
        # Suicide - illegal unless we captured something
        if not captured:
            return None

    return new_board

def _count_territory(board: List[List[str]], player: int) -> int:
    """Count territory controlled by player (area scoring)."""
    stone = STONES[player]
    visited = set()
    territory = 0

    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            if board[r][c] == stone:
                territory += 1  # Count own stones
            elif board[r][c] == '' and (r, c) not in visited:
                # Flood fill empty region
                region = set()
                borders_black = False
                borders_white = False
                stack = [(r, c)]

                while stack:
                    cr, cc = stack.pop()
                    if (cr, cc) in region:
                        continue
                    if board[cr][cc] == 'B':
                        borders_black = True
                        continue
                    if board[cr][cc] == 'W':
                        borders_white = True
                        continue

                    region.add((cr, cc))
                    for nr, nc in _neighbors(cr, cc):
                        if (nr, nc) not in region:
                            stack.append((nr, nc))

                visited.update(region)

                # Region belongs to player if only bordered by their stones
                if player == P0 and borders_black and not borders_white:
                    territory += len(region)
                elif player == P1 and borders_white and not borders_black:
                    territory += len(region)

    return territory

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        'board': [['' for _ in range(BOARD_SIZE)] for _ in range(BOARD_SIZE)],
        'current_player': P0,
        'previous_board_hash': None,  # For ko detection
        'passes': 0,  # Consecutive passes
        'captures': {P0: 0, P1: 0},  # Captured stones
        'is_terminal': False
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = {
        'board': [row[:] for row in state['board']],
        'current_player': 1 - state['current_player'],
        'previous_board_hash': _board_hash(state['board']),
        'passes': state['passes'],
        'captures': state['captures'].copy(),
        'is_terminal': False
    }

    if action == 'pass':
        new_state['passes'] = state['passes'] + 1
        if new_state['passes'] >= 2:
            new_state['is_terminal'] = True
            new_state['current_player'] = TERMINAL
        return new_state

    # Reset pass counter on placement
    new_state['passes'] = 0

    # Parse placement
    _, r_str, c_str = action.split('_')
    r, c = int(r_str), int(c_str)
    player = state['current_player']

    # Count captures before move
    old_opponent_count = sum(
        1 for rr in range(BOARD_SIZE) for cc in range(BOARD_SIZE)
        if state['board'][rr][cc] == STONES[1 - player]
    )

    # Apply move
    new_board = _apply_move(state['board'], r, c, player)
    new_state['board'] = new_board

    # Count captures after move
    new_opponent_count = sum(
        1 for rr in range(BOARD_SIZE) for cc in range(BOARD_SIZE)
        if new_board[rr][cc] == STONES[1 - player]
    )
    captured = old_opponent_count - new_opponent_count
    new_state['captures'][player] = state['captures'][player] + captured

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state['current_player']

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0 (Black)"
    if player_id == P1: return "Player 1 (White)"
    return "Terminal"

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state['is_terminal']:
        return [0.0, 0.0]

    # Area scoring
    black_score = _count_territory(state['board'], P0)
    white_score = _count_territory(state['board'], P1) + KOMI

    if black_score > white_score:
        return [1.0, -1.0]
    else:
        return [-1.0, 1.0]

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state['is_terminal']:
        return []

    actions = ['pass']
    player = state['current_player']
    board = state['board']
    prev_hash = state['previous_board_hash']

    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            if board[r][c] != '':
                continue

            # Try the move
            new_board = _apply_move(board, r, c, player)

            if new_board is None:
                continue  # Suicide

            # Check ko
            if prev_hash is not None and _board_hash(new_board) == prev_hash:
                continue  # Ko violation

            actions.append(f'place_{r}_{c}')

    return actions

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Go is perfect information."""
    obs = {
        'board': state['board'],
        'captures': state['captures'],
        'passes': state['passes']
    }
    return [obs, obs]

from typing import Any, Dict, List, Optional, Tuple

Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Board constants
ROWS = 8
COLS = 8
EMPTY = -1
WHITE = 0  # Player 0, moves up (toward row 8)
BLACK = 1  # Player 1, moves down (toward row 1)

def _pos_to_notation(row: int, col: int) -> str:
    """Convert 0-indexed (row, col) to chess notation like 'e2'."""
    return chr(ord('a') + col) + str(row + 1)

def _notation_to_pos(notation: str) -> Tuple[int, int]:
    """Convert chess notation 'e2' to 0-indexed (row, col)."""
    col = ord(notation[0]) - ord('a')
    row = int(notation[1]) - 1
    return row, col

def _create_initial_board() -> List[List[int]]:
    """Create starting board with pieces in first two rows for each player."""
    board = [[EMPTY for _ in range(COLS)] for _ in range(ROWS)]
    # White pieces on rows 0 and 1 (rows 1-2 in notation)
    for r in range(2):
        for c in range(COLS):
            board[r][c] = WHITE
    # Black pieces on rows 6 and 7 (rows 7-8 in notation)
    for r in range(6, 8):
        for c in range(COLS):
            board[r][c] = BLACK
    return board

def get_initial_state() -> State:
    """Returns the initial game state."""
    return {
        "board": _create_initial_board(),
        "current_player": WHITE,
        "winner": None,
        "terminal": False
    }

def get_current_player(state: State) -> int:
    """Returns current player (0 or 1), or -4 for terminal."""
    if state["terminal"]:
        return -4
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == WHITE:
        return "White"
    elif player_id == BLACK:
        return "Black"
    return "Unknown"

def _count_pieces(board: List[List[int]], player: int) -> int:
    """Count pieces belonging to a player."""
    count = 0
    for row in board:
        for cell in row:
            if cell == player:
                count += 1
    return count

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current player."""
    if state["terminal"]:
        return []

    board = state["board"]
    player = state["current_player"]
    actions = []

    # Direction: White moves up (+1 row), Black moves down (-1 row)
    dr = 1 if player == WHITE else -1

    for r in range(ROWS):
        for c in range(COLS):
            if board[r][c] != player:
                continue

            src = _pos_to_notation(r, c)
            new_r = r + dr

            if new_r < 0 or new_r >= ROWS:
                continue

            # Forward straight move (only if empty)
            if board[new_r][c] == EMPTY:
                dst = _pos_to_notation(new_r, c)
                actions.append(f"{src}-{dst}")

            # Forward diagonal moves (can move to empty or capture opponent)
            for dc in [-1, 1]:
                new_c = c + dc
                if new_c < 0 or new_c >= COLS:
                    continue

                target = board[new_r][new_c]
                dst = _pos_to_notation(new_r, new_c)

                if target == EMPTY:
                    # Regular diagonal move
                    actions.append(f"{src}-{dst}")
                elif target == 1 - player:
                    # Capture (diagonal only)
                    actions.append(f"{src}x{dst}")

    return sorted(actions)

def _check_winner(board: List[List[int]], player: int, new_r: int) -> Optional[int]:
    """Check if player has won by reaching back row or eliminating opponent."""
    # Win by reaching opponent's back row
    if player == WHITE and new_r == ROWS - 1:
        return WHITE
    if player == BLACK and new_r == 0:
        return BLACK

    # Win by eliminating all opponent pieces
    opponent = 1 - player
    if _count_pieces(board, opponent) == 0:
        return player

    return None

def apply_action(state: State, action: Action) -> State:
    """Apply action and return new state."""
    if state["terminal"]:
        return state

    player = state["current_player"]

    # Parse action: "e2-e3" or "e2xd3"
    is_capture = 'x' in action
    parts = action.split('x' if is_capture else '-')
    src_r, src_c = _notation_to_pos(parts[0])
    dst_r, dst_c = _notation_to_pos(parts[1])

    # Copy board
    new_board = [row[:] for row in state["board"]]

    # Move piece
    new_board[dst_r][dst_c] = player
    new_board[src_r][src_c] = EMPTY

    # Check for winner
    winner = _check_winner(new_board, player, dst_r)
    terminal = winner is not None

    # Also check if opponent has no pieces (already handled in _check_winner)
    # Or if opponent has no legal moves (stalemate = opponent loses)
    if not terminal:
        next_player = 1 - player
        # Quick check: does opponent have any pieces?
        if _count_pieces(new_board, next_player) == 0:
            winner = player
            terminal = True

    return {
        "board": new_board,
        "current_player": 1 - player if not terminal else -4,
        "winner": winner,
        "terminal": terminal
    }

def get_rewards(state: State) -> List[float]:
    """Returns rewards [white_reward, black_reward]."""
    if not state["terminal"]:
        return [0.0, 0.0]

    winner = state["winner"]
    if winner == WHITE:
        return [1.0, -1.0]
    elif winner == BLACK:
        return [-1.0, 1.0]
    else:
        return [0.0, 0.0]

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns observations. Perfect info game, both players see same state."""
    obs = {
        "board": [row[:] for row in state["board"]],
        "current_player": state["current_player"],
        "terminal": state["terminal"]
    }
    return [obs, obs]

from typing import Any, Dict, List, Optional, Tuple
import random

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, CHANCE, TERMINAL = 0, 1, -1, -4
VALUATIONS = [1, 2, 3, 4, 5]
BID_RANGE = [0, 1, 2, 3, 4, 5]

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        "valuations": [],  # [P0_valuation, P1_valuation]
        "bids": [],        # [P0_bid, P1_bid]
        "current_player": CHANCE,
        "is_terminal": False
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = {
        "valuations": state["valuations"].copy() if state["valuations"] else [],
        "bids": state["bids"].copy() if state["bids"] else [],
        "current_player": state["current_player"],
        "is_terminal": state["is_terminal"]
    }

    if state["current_player"] == CHANCE:
        # Parse valuation deal "VxVy"
        v0, v1 = int(action[0]), int(action[1])
        new_state["valuations"] = [v0, v1]
        new_state["current_player"] = P0
    elif state["current_player"] == P0:
        # Parse bid "bid_N"
        bid = int(action.split("_")[1])
        new_state["bids"] = [bid]
        new_state["current_player"] = P1
    elif state["current_player"] == P1:
        bid = int(action.split("_")[1])
        new_state["bids"] = state["bids"] + [bid]
        new_state["current_player"] = TERMINAL
        new_state["is_terminal"] = True

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, with -1 for chance and -4 for terminal."""
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    names = {P0: "Player 0", P1: "Player 1", CHANCE: "Chance", TERMINAL: "Terminal"}
    return names.get(player_id, "Unknown")

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state["is_terminal"]:
        return [0.0, 0.0]

    v0, v1 = state["valuations"]
    b0, b1 = state["bids"]

    # Determine winner (P0 wins ties)
    if b0 >= b1:
        winner = P0
        winning_bid = b0
        winner_valuation = v0
    else:
        winner = P1
        winning_bid = b1
        winner_valuation = v1

    # Winner gets valuation - bid, loser gets negative of that (zero-sum normalization)
    winner_utility = float(winner_valuation - winning_bid)
    rewards = [0.0, 0.0]
    rewards[winner] = winner_utility / 2
    rewards[1 - winner] = -winner_utility / 2
    return rewards

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state["is_terminal"]:
        return []

    if state["current_player"] == CHANCE:
        # All possible valuation pairs
        return [f"{v0}{v1}" for v0 in VALUATIONS for v1 in VALUATIONS]

    # Player bids
    return [f"bid_{b}" for b in BID_RANGE]

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Players see only their own valuation and bid."""
    if state["current_player"] == CHANCE:
        return [{}, {}]

    valuations = state["valuations"]
    bids = state["bids"]

    if state["is_terminal"]:
        # At terminal, reveal all information
        return [
            {"my_valuation": valuations[0], "my_bid": bids[0],
             "opponent_valuation": valuations[1], "opponent_bid": bids[1]},
            {"my_valuation": valuations[1], "my_bid": bids[1],
             "opponent_valuation": valuations[0], "opponent_bid": bids[0]}
        ]

    # During play, players only see their valuation and their own bid
    p0_obs = {"my_valuation": valuations[0]}
    p1_obs = {"my_valuation": valuations[1]}

    if len(bids) >= 1:
        p0_obs["my_bid"] = bids[0]
    if len(bids) >= 2:
        p1_obs["my_bid"] = bids[1]

    return [p0_obs, p1_obs]

def resample_history(obs_action_history: List[Tuple[PlayerObservation, Optional[Action]]], player_id: int) -> List[Action]:
    """Stochastically sample a history consistent with player_id's view."""
    if not obs_action_history:
        return []

    last_obs, last_action = obs_action_history[-1]
    my_valuation = last_obs.get("my_valuation")

    # Sample opponent's valuation uniformly
    opponent_valuation = random.choice(VALUATIONS)

    # Construct deal action
    if player_id == P0:
        deal = f"{my_valuation}{opponent_valuation}"
    else:
        deal = f"{opponent_valuation}{my_valuation}"

    history = [deal]

    # Add bids
    my_bid = last_obs.get("my_bid")
    opponent_bid = last_obs.get("opponent_bid")

    if player_id == P0:
        if my_bid is not None:
            history.append(f"bid_{my_bid}")
        if opponent_bid is not None:
            history.append(f"bid_{opponent_bid}")
        elif my_bid is not None:
            # Opponent has bid but we don't know it yet - sample
            history.append(f"bid_{random.choice(BID_RANGE)}")
    else:
        if opponent_bid is not None:
            history.append(f"bid_{opponent_bid}")
        else:
            # P0 has bid but we don't know it
            history.append(f"bid_{random.choice(BID_RANGE)}")
        if my_bid is not None:
            history.append(f"bid_{my_bid}")

    if last_action is not None and (not history or history[-1] != last_action):
        history.append(last_action)

    return history

from typing import Any, Dict, List, Optional
import copy

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
BOARD_SIZE = 6
QUAD_SIZE = 3
MARKS = {P0: 'x', P1: 'o'}
WIN_LENGTH = 5

# Quadrant boundaries: (row_start, row_end, col_start, col_end)
QUADRANTS = {
    0: (0, 3, 0, 3),   # top-left
    1: (0, 3, 3, 6),   # top-right
    2: (3, 6, 0, 3),   # bottom-left
    3: (3, 6, 3, 6),   # bottom-right
}

def _rotate_quadrant(board: List[List[str]], quad: int, clockwise: bool) -> List[List[str]]:
    """Rotate a quadrant 90 degrees."""
    new_board = [row[:] for row in board]
    r_start, r_end, c_start, c_end = QUADRANTS[quad]

    # Extract quadrant
    quadrant = [[board[r][c] for c in range(c_start, c_end)]
                for r in range(r_start, r_end)]

    # Rotate
    if clockwise:
        rotated = [[quadrant[QUAD_SIZE-1-j][i] for j in range(QUAD_SIZE)]
                   for i in range(QUAD_SIZE)]
    else:
        rotated = [[quadrant[j][QUAD_SIZE-1-i] for j in range(QUAD_SIZE)]
                   for i in range(QUAD_SIZE)]

    # Place back
    for i in range(QUAD_SIZE):
        for j in range(QUAD_SIZE):
            new_board[r_start + i][c_start + j] = rotated[i][j]

    return new_board

def _check_five_in_row(board: List[List[str]], mark: str) -> bool:
    """Check if the given mark has 5 in a row."""
    # Check all rows
    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE - WIN_LENGTH + 1):
            if all(board[r][c+i] == mark for i in range(WIN_LENGTH)):
                return True

    # Check all columns
    for c in range(BOARD_SIZE):
        for r in range(BOARD_SIZE - WIN_LENGTH + 1):
            if all(board[r+i][c] == mark for i in range(WIN_LENGTH)):
                return True

    # Check diagonals (top-left to bottom-right)
    for r in range(BOARD_SIZE - WIN_LENGTH + 1):
        for c in range(BOARD_SIZE - WIN_LENGTH + 1):
            if all(board[r+i][c+i] == mark for i in range(WIN_LENGTH)):
                return True

    # Check anti-diagonals (top-right to bottom-left)
    for r in range(BOARD_SIZE - WIN_LENGTH + 1):
        for c in range(WIN_LENGTH - 1, BOARD_SIZE):
            if all(board[r+i][c-i] == mark for i in range(WIN_LENGTH)):
                return True

    return False

def _is_full(board: List[List[str]]) -> bool:
    """Check if board is full."""
    return all(board[r][c] != '' for r in range(BOARD_SIZE) for c in range(BOARD_SIZE))

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        'board': [['' for _ in range(BOARD_SIZE)] for _ in range(BOARD_SIZE)],
        'current_player': P0,
        'status': 'ongoing'  # ongoing, x_won, o_won, draw
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    # Parse action: "mark(row,col)_rotate_Q_D"
    parts = action.split('_rotate_')
    place_part = parts[0]  # "mark(row,col)"
    rotate_part = parts[1]  # "Q_D"

    # Parse placement
    mark = place_part[0]
    coords = place_part[2:-1]  # "row,col"
    r, c = map(int, coords.split(','))

    # Parse rotation
    rot_parts = rotate_part.split('_')
    quad = int(rot_parts[0])
    direction = rot_parts[1]
    clockwise = (direction == "CW")

    # Create new board and place
    new_board = [row[:] for row in state['board']]
    new_board[r][c] = mark

    # Rotate
    new_board = _rotate_quadrant(new_board, quad, clockwise)

    new_state = {
        'board': new_board,
        'current_player': 1 - state['current_player'],
        'status': 'ongoing'
    }

    # Check win conditions
    x_wins = _check_five_in_row(new_board, 'x')
    o_wins = _check_five_in_row(new_board, 'o')

    if x_wins and o_wins:
        new_state['status'] = 'draw'
        new_state['current_player'] = TERMINAL
    elif x_wins:
        new_state['status'] = 'x_won'
        new_state['current_player'] = TERMINAL
    elif o_wins:
        new_state['status'] = 'o_won'
        new_state['current_player'] = TERMINAL
    elif _is_full(new_board):
        new_state['status'] = 'draw'
        new_state['current_player'] = TERMINAL

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state['current_player']

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0 (X)"
    if player_id == P1: return "Player 1 (O)"
    return "Terminal"

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    status = state['status']
    if status == 'x_won':
        return [1.0, -1.0]
    elif status == 'o_won':
        return [-1.0, 1.0]
    return [0.0, 0.0]  # Draw or ongoing

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state['current_player'] == TERMINAL:
        return []

    mark = MARKS[state['current_player']]
    actions = []

    # All combinations of: empty cell × quadrant × direction
    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            if state['board'][r][c] == '':
                for quad in range(4):
                    for direction in ['CW', 'CCW']:
                        actions.append(f"{mark}({r},{c})_rotate_{quad}_{direction}")

    return actions

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Pentago is perfect information."""
    obs = {'board': state['board'], 'status': state['status']}
    return [obs, obs]

from typing import Any, Dict, List, Optional, Tuple
import copy

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
BOARD_SIZE = 8
PIECES = {P0: 'r', P1: 'b'}  # red, black
KINGS = {P0: 'R', P1: 'B'}
NO_CAPTURE_DRAW_LIMIT = 40

def _is_valid_square(r: int, c: int) -> bool:
    """Check if position is on board."""
    return 0 <= r < BOARD_SIZE and 0 <= c < BOARD_SIZE

def _is_dark_square(r: int, c: int) -> bool:
    """Dark squares are playable (where (r+c) is odd)."""
    return (r + c) % 2 == 1

def _get_piece_owner(piece: str) -> Optional[int]:
    """Return owner of piece, or None if empty."""
    if piece in ('r', 'R'): return P0
    if piece in ('b', 'B'): return P1
    return None

def _is_king(piece: str) -> bool:
    """Check if piece is a king."""
    return piece in ('R', 'B')

def _get_forward_dirs(player: int) -> List[int]:
    """Get forward row directions for player."""
    return [-1] if player == P0 else [1]

def _get_all_dirs(player: int, is_king: bool) -> List[int]:
    """Get all valid row directions for a piece."""
    if is_king:
        return [-1, 1]
    return _get_forward_dirs(player)

def _find_jumps(board: List[List[str]], r: int, c: int, player: int,
                path: List[Tuple[int, int]], captured: set) -> List[List[Tuple[int, int]]]:
    """Find all possible jump sequences from position."""
    piece = board[r][c]
    is_king = _is_king(piece)
    row_dirs = _get_all_dirs(player, is_king)

    jumps = []
    for dr in row_dirs:
        for dc in [-1, 1]:
            mr, mc = r + dr, c + dc  # middle (captured) position
            er, ec = r + 2*dr, c + 2*dc  # end position

            if not _is_valid_square(er, ec):
                continue
            if (mr, mc) in captured:
                continue

            middle_piece = board[mr][mc]
            end_piece = board[er][ec]

            if (middle_piece != '' and
                _get_piece_owner(middle_piece) != player and
                end_piece == ''):

                new_path = path + [(er, ec)]
                new_captured = captured | {(mr, mc)}

                # Recursively find more jumps
                more_jumps = _find_jumps(board, er, ec, player, new_path, new_captured)

                if more_jumps:
                    jumps.extend(more_jumps)
                else:
                    jumps.append(new_path)

    return jumps

def _get_all_jumps(board: List[List[str]], player: int) -> List[Action]:
    """Get all jump actions for player."""
    actions = []
    piece_chars = (PIECES[player], KINGS[player])

    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            if board[r][c] in piece_chars:
                jump_sequences = _find_jumps(board, r, c, player, [(r, c)], set())
                for seq in jump_sequences:
                    action = "jump_" + "_".join(f"{pr}_{pc}" for pr, pc in seq)
                    actions.append(action)

    return actions

def _get_all_moves(board: List[List[str]], player: int) -> List[Action]:
    """Get all simple move actions for player."""
    actions = []
    piece_chars = (PIECES[player], KINGS[player])

    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            piece = board[r][c]
            if piece in piece_chars:
                is_king = _is_king(piece)
                row_dirs = _get_all_dirs(player, is_king)

                for dr in row_dirs:
                    for dc in [-1, 1]:
                        nr, nc = r + dr, c + dc
                        if _is_valid_square(nr, nc) and board[nr][nc] == '':
                            actions.append(f"move_{r}_{c}_{nr}_{nc}")

    return actions

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    board = [['' for _ in range(BOARD_SIZE)] for _ in range(BOARD_SIZE)]

    # Place black pieces (rows 0-2)
    for r in range(3):
        for c in range(BOARD_SIZE):
            if _is_dark_square(r, c):
                board[r][c] = 'b'

    # Place red pieces (rows 5-7)
    for r in range(5, 8):
        for c in range(BOARD_SIZE):
            if _is_dark_square(r, c):
                board[r][c] = 'r'

    return {
        'board': board,
        'current_player': P0,
        'no_capture_count': 0,
        'status': 'ongoing'
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_board = [row[:] for row in state['board']]
    current = state['current_player']
    no_capture_count = state['no_capture_count']

    parts = action.split('_')
    is_jump = (parts[0] == 'jump')

    if is_jump:
        # Parse jump path
        coords = []
        i = 1
        while i < len(parts):
            coords.append((int(parts[i]), int(parts[i+1])))
            i += 2

        piece = new_board[coords[0][0]][coords[0][1]]
        new_board[coords[0][0]][coords[0][1]] = ''

        # Process each jump in the chain
        for i in range(len(coords) - 1):
            sr, sc = coords[i]
            er, ec = coords[i + 1]
            # Remove captured piece
            mr, mc = (sr + er) // 2, (sc + ec) // 2
            new_board[mr][mc] = ''

        # Place piece at final position
        final_r, final_c = coords[-1]

        # Check for promotion
        if (current == P0 and final_r == 0) or (current == P1 and final_r == 7):
            piece = KINGS[current]

        new_board[final_r][final_c] = piece
        no_capture_count = 0  # Reset on capture

    else:
        # Simple move
        _, sr, sc, er, ec = parts
        sr, sc, er, ec = int(sr), int(sc), int(er), int(ec)

        piece = new_board[sr][sc]
        new_board[sr][sc] = ''

        # Check for promotion
        if (current == P0 and er == 0) or (current == P1 and er == 7):
            piece = KINGS[current]

        new_board[er][ec] = piece
        no_capture_count += 1

    new_state = {
        'board': new_board,
        'current_player': 1 - current,
        'no_capture_count': no_capture_count,
        'status': 'ongoing'
    }

    # Check game over conditions
    opponent = 1 - current
    opponent_pieces = (PIECES[opponent], KINGS[opponent])
    has_opponent_pieces = any(
        new_board[r][c] in opponent_pieces
        for r in range(BOARD_SIZE) for c in range(BOARD_SIZE)
    )

    if not has_opponent_pieces:
        # Current player wins - captured all pieces
        new_state['status'] = f'p{current}_won'
        new_state['current_player'] = TERMINAL
    elif no_capture_count >= NO_CAPTURE_DRAW_LIMIT:
        new_state['status'] = 'draw'
        new_state['current_player'] = TERMINAL
    else:
        # Check if opponent can move
        opponent_actions = get_legal_actions(new_state)
        if not opponent_actions:
            # Opponent blocked - current player wins
            new_state['status'] = f'p{current}_won'
            new_state['current_player'] = TERMINAL

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state['current_player']

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0 (Red)"
    if player_id == P1: return "Player 1 (Black)"
    return "Terminal"

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    status = state['status']
    if status == 'p0_won':
        return [1.0, -1.0]
    elif status == 'p1_won':
        return [-1.0, 1.0]
    return [0.0, 0.0]

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state['current_player'] == TERMINAL:
        return []

    player = state['current_player']
    board = state['board']

    # Jumps are mandatory if available
    jumps = _get_all_jumps(board, player)
    if jumps:
        return jumps

    # Otherwise, simple moves
    return _get_all_moves(board, player)

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Checkers is perfect information."""
    obs = {
        'board': state['board'],
        'status': state['status'],
        'no_capture_count': state['no_capture_count']
    }
    return [obs, obs]

from typing import Any, Dict, List, Optional, Tuple

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
BOARD_SIZE = 5
FILES = 'abcde'
RANKS = '12345'

# Piece characters
WHITE_PIECES = 'KQRBNP'
BLACK_PIECES = 'kqrbnp'

def _pos_to_algebraic(r: int, c: int) -> str:
    """Convert (row, col) to algebraic notation."""
    return FILES[c] + RANKS[r]

def _algebraic_to_pos(sq: str) -> Tuple[int, int]:
    """Convert algebraic to (row, col)."""
    c = FILES.index(sq[0])
    r = RANKS.index(sq[1])
    return (r, c)

def _is_white(piece: str) -> bool:
    return piece in WHITE_PIECES

def _is_black(piece: str) -> bool:
    return piece in BLACK_PIECES

def _owner(piece: str) -> Optional[int]:
    if _is_white(piece): return P0
    if _is_black(piece): return P1
    return None

def _piece_type(piece: str) -> str:
    return piece.upper()

def _in_bounds(r: int, c: int) -> bool:
    return 0 <= r < BOARD_SIZE and 0 <= c < BOARD_SIZE

def _find_king(board: List[List[str]], player: int) -> Optional[Tuple[int, int]]:
    """Find king's position."""
    king = 'K' if player == P0 else 'k'
    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            if board[r][c] == king:
                return (r, c)
    return None

def _is_attacked(board: List[List[str]], r: int, c: int, by_player: int) -> bool:
    """Check if square is attacked by player."""
    for rr in range(BOARD_SIZE):
        for cc in range(BOARD_SIZE):
            piece = board[rr][cc]
            if piece == '' or _owner(piece) != by_player:
                continue
            if _can_attack(board, rr, cc, r, c):
                return True
    return False

def _can_attack(board: List[List[str]], fr: int, fc: int, tr: int, tc: int) -> bool:
    """Check if piece at (fr,fc) can attack (tr,tc)."""
    piece = board[fr][fc]
    pt = _piece_type(piece)
    dr, dc = tr - fr, tc - fc

    if pt == 'P':
        direction = 1 if _is_white(piece) else -1
        return dr == direction and abs(dc) == 1

    if pt == 'N':
        return (abs(dr), abs(dc)) in [(1, 2), (2, 1)]

    if pt == 'K':
        return abs(dr) <= 1 and abs(dc) <= 1 and (dr != 0 or dc != 0)

    if pt == 'R':
        if dr != 0 and dc != 0:
            return False
        return _path_clear(board, fr, fc, tr, tc)

    if pt == 'B':
        if abs(dr) != abs(dc) or dr == 0:
            return False
        return _path_clear(board, fr, fc, tr, tc)

    if pt == 'Q':
        if dr == 0 or dc == 0 or abs(dr) == abs(dc):
            return _path_clear(board, fr, fc, tr, tc)
        return False

    return False

def _path_clear(board: List[List[str]], fr: int, fc: int, tr: int, tc: int) -> bool:
    """Check if path is clear."""
    dr = 0 if tr == fr else (1 if tr > fr else -1)
    dc = 0 if tc == fc else (1 if tc > fc else -1)

    r, c = fr + dr, fc + dc
    while (r, c) != (tr, tc):
        if board[r][c] != '':
            return False
        r, c = r + dr, c + dc
    return True

def _in_check(board: List[List[str]], player: int) -> bool:
    """Check if player's king is in check."""
    king_pos = _find_king(board, player)
    if king_pos is None:
        return True
    return _is_attacked(board, king_pos[0], king_pos[1], 1 - player)

def _get_piece_moves(state: State, fr: int, fc: int) -> List[Action]:
    """Get moves for piece at (fr, fc)."""
    board = state['board']
    piece = board[fr][fc]
    player = _owner(piece)
    pt = _piece_type(piece)
    moves = []
    from_sq = _pos_to_algebraic(fr, fc)

    if pt == 'P':
        direction = 1 if player == P0 else -1
        start_rank = 1 if player == P0 else 3
        promo_rank = 4 if player == P0 else 0

        # Forward one
        nr = fr + direction
        if _in_bounds(nr, fc) and board[nr][fc] == '':
            if nr == promo_rank:
                for promo in 'QRBN':
                    moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, fc)}_{promo}")
            else:
                moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, fc)}")

            # Forward two from start
            if fr == start_rank:
                nr2 = fr + 2 * direction
                if _in_bounds(nr2, fc) and board[nr2][fc] == '':
                    moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr2, fc)}")

        # Captures
        for dc in [-1, 1]:
            nr, nc = fr + direction, fc + dc
            if not _in_bounds(nr, nc):
                continue

            target = board[nr][nc]
            ep = state.get('en_passant')
            if (target != '' and _owner(target) != player) or (ep and ep == (nr, nc)):
                if nr == promo_rank:
                    for promo in 'QRBN':
                        moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, nc)}_{promo}")
                else:
                    moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, nc)}")

    elif pt == 'N':
        for dr, dc in [(-2, -1), (-2, 1), (-1, -2), (-1, 2),
                       (1, -2), (1, 2), (2, -1), (2, 1)]:
            nr, nc = fr + dr, fc + dc
            if _in_bounds(nr, nc):
                target = board[nr][nc]
                if target == '' or _owner(target) != player:
                    moves.append(f"N_{from_sq}_{_pos_to_algebraic(nr, nc)}")

    elif pt == 'K':
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                if dr == 0 and dc == 0:
                    continue
                nr, nc = fr + dr, fc + dc
                if _in_bounds(nr, nc):
                    target = board[nr][nc]
                    if target == '' or _owner(target) != player:
                        moves.append(f"K_{from_sq}_{_pos_to_algebraic(nr, nc)}")

    elif pt in 'RBQ':
        directions = []
        if pt in 'RQ':
            directions.extend([(0, 1), (0, -1), (1, 0), (-1, 0)])
        if pt in 'BQ':
            directions.extend([(1, 1), (1, -1), (-1, 1), (-1, -1)])

        for dr, dc in directions:
            nr, nc = fr + dr, fc + dc
            while _in_bounds(nr, nc):
                target = board[nr][nc]
                if target == '':
                    moves.append(f"{pt}_{from_sq}_{_pos_to_algebraic(nr, nc)}")
                elif _owner(target) != player:
                    moves.append(f"{pt}_{from_sq}_{_pos_to_algebraic(nr, nc)}")
                    break
                else:
                    break
                nr, nc = nr + dr, nc + dc

    return moves

def _generate_moves(state: State, only_legal: bool = True) -> List[Action]:
    """Generate all moves for current player."""
    board = state['board']
    player = state['current_player']
    moves = []

    for fr in range(BOARD_SIZE):
        for fc in range(BOARD_SIZE):
            piece = board[fr][fc]
            if piece == '' or _owner(piece) != player:
                continue
            moves.extend(_get_piece_moves(state, fr, fc))

    if only_legal:
        legal_moves = []
        for move in moves:
            new_state = _apply_move_unchecked(state, move)
            if not _in_check(new_state['board'], player):
                legal_moves.append(move)
        return legal_moves

    return moves

def _apply_move_unchecked(state: State, action: Action) -> State:
    """Apply move without checking legality."""
    new_board = [row[:] for row in state['board']]
    player = state['current_player']
    new_ep = None
    new_halfmove = state['halfmove_clock'] + 1

    parts = action.split('_')
    piece_char = parts[0]
    from_sq = parts[1]
    to_sq = parts[2]
    promo = parts[3] if len(parts) > 3 else None

    fr, fc = _algebraic_to_pos(from_sq)
    tr, tc = _algebraic_to_pos(to_sq)

    piece = new_board[fr][fc]
    captured = new_board[tr][tc]

    # En passant capture
    if piece_char == 'P' and state.get('en_passant') == (tr, tc):
        new_board[fr][tc] = ''
        new_halfmove = 0

    new_board[fr][fc] = ''

    # Promotion
    if promo:
        piece = promo if player == P0 else promo.lower()
        new_halfmove = 0

    new_board[tr][tc] = piece

    # Reset halfmove on pawn move or capture
    if piece_char == 'P' or captured != '':
        new_halfmove = 0

    # Set en passant square
    if piece_char == 'P' and abs(tr - fr) == 2:
        new_ep = ((fr + tr) // 2, fc)

    return {
        'board': new_board,
        'current_player': 1 - player,
        'en_passant': new_ep,
        'halfmove_clock': new_halfmove,
        'is_terminal': False,
        'result': None
    }

def _insufficient_material(board: List[List[str]]) -> bool:
    """Check for insufficient material."""
    pieces = []
    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            p = board[r][c]
            if p != '':
                pieces.append(p.upper())
    pieces.sort()

    if pieces == ['K', 'K']:
        return True
    if pieces in [['B', 'K', 'K'], ['K', 'K', 'N']]:
        return True
    return False

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    board = [['' for _ in range(BOARD_SIZE)] for _ in range(BOARD_SIZE)]

    # White pieces (rank 1)
    board[0] = ['R', 'N', 'B', 'Q', 'K']
    board[1] = ['P'] * 5

    # Black pieces (rank 5)
    board[3] = ['p'] * 5
    board[4] = ['r', 'n', 'b', 'q', 'k']

    return {
        'board': board,
        'current_player': P0,
        'en_passant': None,
        'halfmove_clock': 0,
        'is_terminal': False,
        'result': None
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = _apply_move_unchecked(state, action)

    # Check for game end
    opponent = new_state['current_player']
    legal_moves = _generate_moves(new_state, only_legal=True)

    if len(legal_moves) == 0:
        new_state['is_terminal'] = True
        new_state['current_player'] = TERMINAL
        if _in_check(new_state['board'], opponent):
            new_state['result'] = 'white' if opponent == P1 else 'black'
        else:
            new_state['result'] = 'draw'
    elif new_state['halfmove_clock'] >= 100:
        new_state['is_terminal'] = True
        new_state['current_player'] = TERMINAL
        new_state['result'] = 'draw'
    elif _insufficient_material(new_state['board']):
        new_state['is_terminal'] = True
        new_state['current_player'] = TERMINAL
        new_state['result'] = 'draw'

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state['current_player']

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0 (White)"
    if player_id == P1: return "Player 1 (Black)"
    return "Terminal"

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state['is_terminal']:
        return [0.0, 0.0]

    result = state['result']
    if result == 'white':
        return [1.0, -1.0]
    elif result == 'black':
        return [-1.0, 1.0]
    else:
        return [0.0, 0.0]

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state['is_terminal']:
        return []
    return _generate_moves(state, only_legal=True)

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Chess is perfect information."""
    obs = {
        'board': state['board'],
        'en_passant': state['en_passant'],
        'halfmove_clock': state['halfmove_clock']
    }
    return [obs, obs]

from typing import Any, Dict, List, Optional, Tuple
import random

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, CHANCE, TERMINAL = 0, 1, -1, -4
ITEM_COUNTS = {"books": 2, "hats": 2, "balls": 2}
VALUE_RANGE = [0, 1, 2, 3]
MAX_ROUNDS = 10  # Prevent infinite negotiation

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        "valuations": {},     # {"p0": [b,h,l], "p1": [b,h,l]}
        "current_proposal": None,  # {"proposer": 0/1, "division": [b,h,l]}
        "proposer": None,     # Who made the current proposal
        "current_player": CHANCE,
        "round": 0,
        "outcome": None,      # "accepted", "rejected", or None
        "is_terminal": False
    }

def _parse_valuation_action(action: str) -> Dict:
    """Parse 'v0_A_B_C_v1_D_E_F' into valuations dict."""
    parts = action.split("_")
    return {
        "p0": [int(parts[1]), int(parts[2]), int(parts[3])],
        "p1": [int(parts[5]), int(parts[6]), int(parts[7])]
    }

def _parse_proposal(action: str) -> List[int]:
    """Parse 'propose_X_Y_Z' into [books, hats, balls] for proposer."""
    parts = action.split("_")
    return [int(parts[1]), int(parts[2]), int(parts[3])]

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = {
        "valuations": state["valuations"].copy() if state["valuations"] else {},
        "current_proposal": state["current_proposal"],
        "proposer": state["proposer"],
        "current_player": state["current_player"],
        "round": state["round"],
        "outcome": state["outcome"],
        "is_terminal": state["is_terminal"]
    }

    if state["current_player"] == CHANCE:
        new_state["valuations"] = _parse_valuation_action(action)
        new_state["current_player"] = P0
        return new_state

    current = state["current_player"]

    if action == "accept":
        new_state["outcome"] = "accepted"
        new_state["is_terminal"] = True
        new_state["current_player"] = TERMINAL
    elif action == "reject":
        new_state["outcome"] = "rejected"
        new_state["is_terminal"] = True
        new_state["current_player"] = TERMINAL
    elif action.startswith("propose_"):
        division = _parse_proposal(action)
        new_state["current_proposal"] = division
        new_state["proposer"] = current
        new_state["current_player"] = 1 - current
        new_state["round"] = state["round"] + 1

        # Force end if max rounds reached
        if new_state["round"] >= MAX_ROUNDS:
            new_state["outcome"] = "rejected"
            new_state["is_terminal"] = True
            new_state["current_player"] = TERMINAL

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, with -1 for chance and -4 for terminal."""
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    names = {P0: "Player 0", P1: "Player 1", CHANCE: "Chance", TERMINAL: "Terminal"}
    return names.get(player_id, "Unknown")

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state["is_terminal"]:
        return [0.0, 0.0]

    if state["outcome"] == "rejected":
        return [0.0, 0.0]

    # Accepted proposal
    proposal = state["current_proposal"]
    proposer = state["proposer"]
    vals = state["valuations"]

    # Proposer gets proposal amounts, other gets remainder
    proposer_items = proposal
    other_items = [
        ITEM_COUNTS["books"] - proposal[0],
        ITEM_COUNTS["hats"] - proposal[1],
        ITEM_COUNTS["balls"] - proposal[2]
    ]

    if proposer == P0:
        p0_items, p1_items = proposer_items, other_items
    else:
        p0_items, p1_items = other_items, proposer_items

    p0_reward = sum(p0_items[i] * vals["p0"][i] for i in range(3))
    p1_reward = sum(p1_items[i] * vals["p1"][i] for i in range(3))

    # Normalize to zero-sum by subtracting mean
    mean_reward = (p0_reward + p1_reward) / 2
    return [float(p0_reward - mean_reward), float(p1_reward - mean_reward)]

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state["is_terminal"]:
        return []

    if state["current_player"] == CHANCE:
        # Generate all valuation combinations (simplified: just a subset)
        actions = []
        for v0b in VALUE_RANGE:
            for v0h in VALUE_RANGE:
                for v0l in VALUE_RANGE:
                    for v1b in VALUE_RANGE:
                        for v1h in VALUE_RANGE:
                            for v1l in VALUE_RANGE:
                                actions.append(f"v0_{v0b}_{v0h}_{v0l}_v1_{v1b}_{v1h}_{v1l}")
        return actions

    actions = []

    # Can always reject
    actions.append("reject")

    # Can accept if there's a proposal from opponent
    if state["current_proposal"] is not None and state["proposer"] != state["current_player"]:
        actions.append("accept")

    # Can make any valid proposal
    for b in range(ITEM_COUNTS["books"] + 1):
        for h in range(ITEM_COUNTS["hats"] + 1):
            for l in range(ITEM_COUNTS["balls"] + 1):
                actions.append(f"propose_{b}_{h}_{l}")

    return actions

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Players see their own values and proposals."""
    if state["current_player"] == CHANCE:
        return [{}, {}]

    vals = state["valuations"]

    base_obs = {
        "current_proposal": state["current_proposal"],
        "proposer": state["proposer"],
        "round": state["round"]
    }

    p0_obs = {**base_obs, "my_values": vals["p0"]}
    p1_obs = {**base_obs, "my_values": vals["p1"]}

    if state["is_terminal"]:
        p0_obs["opponent_values"] = vals["p1"]
        p1_obs["opponent_values"] = vals["p0"]
        p0_obs["outcome"] = state["outcome"]
        p1_obs["outcome"] = state["outcome"]

    return [p0_obs, p1_obs]

def resample_history(obs_action_history: List[Tuple[PlayerObservation, Optional[Action]]], player_id: int) -> List[Action]:
    """Stochastically sample a history consistent with player_id's view."""
    if not obs_action_history:
        return []

    last_obs, last_action = obs_action_history[-1]
    my_values = last_obs.get("my_values", [0, 0, 0])

    # Sample opponent's values
    opp_values = [random.choice(VALUE_RANGE) for _ in range(3)]

    if player_id == P0:
        deal = f"v0_{my_values[0]}_{my_values[1]}_{my_values[2]}_v1_{opp_values[0]}_{opp_values[1]}_{opp_values[2]}"
    else:
        deal = f"v0_{opp_values[0]}_{opp_values[1]}_{opp_values[2]}_v1_{my_values[0]}_{my_values[1]}_{my_values[2]}"

    history = [deal]

    # Reconstruct the full action history
    # obs_action_history contains (obs, action) only for our turns
    # The observation shows the state BEFORE we act
    # current_proposal/proposer shows opponent's last proposal (if they made one)

    # Track what proposal we last made (to infer opponent responses)
    last_our_proposal = None

    for i, (obs, act) in enumerate(obs_action_history):
        curr_proposal = obs.get("current_proposal")
        curr_proposer = obs.get("proposer")

        # If there's a proposal from opponent visible in our observation,
        # it means opponent made a proposal between our last turn and now
        if curr_proposal is not None and curr_proposer == (1 - player_id):
            # Only add if this is a new opponent proposal
            opp_action = f"propose_{curr_proposal[0]}_{curr_proposal[1]}_{curr_proposal[2]}"
            history.append(opp_action)

        # Add our action
        if act is not None:
            history.append(act)
            # Track if we made a proposal
            if act.startswith("propose_"):
                parts = act.split("_")
                last_our_proposal = [int(parts[1]), int(parts[2]), int(parts[3])]

    return history

from typing import Any, Dict, List, Optional, Tuple
from itertools import permutations
import copy

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, CHANCE, TERMINAL = 0, 1, -1, -4
NUM_POINTS = 24
NUM_CHECKERS = 15
DIE_SIDES = 6

# Initial positions: {point: (count, player)}
# Points are 1-indexed (1-24)
INITIAL_POSITION = {
    # Player 0 checkers
    24: (2, P0),
    13: (5, P0),
    8: (3, P0),
    6: (5, P0),
    # Player 1 checkers
    1: (2, P1),
    12: (5, P1),
    17: (3, P1),
    19: (5, P1),
}

def _get_direction(player: int) -> int:
    """P0 moves counterclockwise (decreasing), P1 moves clockwise (increasing)."""
    return -1 if player == P0 else 1

def _home_range(player: int) -> range:
    """Get home board range for player."""
    return range(1, 7) if player == P0 else range(19, 25)

def _bar_entry_range(player: int) -> range:
    """Get bar entry range (opponent's home board)."""
    return range(19, 25) if player == P0 else range(1, 7)

def _point_after_move(point: int, die: int, player: int) -> int:
    """Calculate destination point after moving die pips."""
    direction = _get_direction(player)
    return point + direction * die

def _can_bear_off(board: Dict[int, Tuple[int, int]], bar: Dict[int, int], player: int) -> bool:
    """Check if player can bear off (all checkers in home)."""
    if bar.get(player, 0) > 0:
        return False

    home = _home_range(player)
    for point in range(1, NUM_POINTS + 1):
        if point not in home:
            count, owner = board.get(point, (0, None))
            if owner == player and count > 0:
                return False
    return True

def _generate_moves_for_dice(board: Dict, bar: Dict, player: int, dice: List[int]) -> List[str]:
    """Generate all legal move combinations for given dice."""
    if not dice:
        return [""]

    moves = set()

    # Try using each die first (order matters for some positions)
    for perm in set(permutations(dice)):
        _find_move_sequences(board, bar, player, list(perm), [], moves)

    if not moves:
        return ["pass"]

    return list(moves)

def _find_move_sequences(board: Dict, bar: Dict, player: int,
                          remaining_dice: List[int], current_moves: List[str],
                          all_moves: set):
    """Recursively find all legal move sequences."""
    if not remaining_dice:
        if current_moves:
            all_moves.add(",".join(current_moves))
        return

    die = remaining_dice[0]
    rest = remaining_dice[1:]
    found_move = False

    # Must move from bar first
    if bar.get(player, 0) > 0:
        entry_point = die if player == P1 else (25 - die)
        if _can_move_to(board, entry_point, player):
            new_board, new_bar = _apply_single_move(board, bar, player, "bar", entry_point)
            move_str = f"bar/{entry_point}"
            _find_move_sequences(new_board, new_bar, player, rest,
                                current_moves + [move_str], all_moves)
            found_move = True
    else:
        # Try moving from each point
        for point in range(1, NUM_POINTS + 1):
            count, owner = board.get(point, (0, None))
            if owner != player or count == 0:
                continue

            dest = _point_after_move(point, die, player)

            # Bearing off
            if _can_bear_off(board, bar, player):
                home = _home_range(player)
                if player == P0:
                    if dest < 1:
                        # Exact or overshoot bearing off
                        if dest == 0 or _no_checkers_behind(board, player, point):
                            new_board, new_bar = _apply_single_move(board, bar, player, point, "off")
                            move_str = f"{point}/off"
                            _find_move_sequences(new_board, new_bar, player, rest,
                                                current_moves + [move_str], all_moves)
                            found_move = True
                            continue
                else:  # P1
                    if dest > 24:
                        if dest == 25 or _no_checkers_behind(board, player, point):
                            new_board, new_bar = _apply_single_move(board, bar, player, point, "off")
                            move_str = f"{point}/off"
                            _find_move_sequences(new_board, new_bar, player, rest,
                                                current_moves + [move_str], all_moves)
                            found_move = True
                            continue

            # Normal move
            if 1 <= dest <= 24 and _can_move_to(board, dest, player):
                new_board, new_bar = _apply_single_move(board, bar, player, point, dest)
                move_str = f"{point}/{dest}"
                _find_move_sequences(new_board, new_bar, player, rest,
                                    current_moves + [move_str], all_moves)
                found_move = True

    # If no move possible with this die, try skipping it
    if not found_move:
        _find_move_sequences(board, bar, player, rest, current_moves, all_moves)

def _no_checkers_behind(board: Dict, player: int, point: int) -> bool:
    """Check if there are no checkers on higher points (for bearing off)."""
    if player == P0:
        for p in range(point + 1, 7):
            count, owner = board.get(p, (0, None))
            if owner == player and count > 0:
                return False
    else:
        for p in range(19, point):
            count, owner = board.get(p, (0, None))
            if owner == player and count > 0:
                return False
    return True

def _can_move_to(board: Dict, point: int, player: int) -> bool:
    """Check if player can move to a point."""
    count, owner = board.get(point, (0, None))
    return count < 2 or owner == player

def _apply_single_move(board: Dict, bar: Dict, player: int,
                        from_pos, to_pos) -> Tuple[Dict, Dict]:
    """Apply a single move and return new board and bar."""
    new_board = copy.deepcopy(board)
    new_bar = bar.copy()

    # Remove from source
    if from_pos == "bar":
        new_bar[player] = new_bar.get(player, 0) - 1
    else:
        count, owner = new_board.get(from_pos, (0, None))
        if count == 1:
            del new_board[from_pos]
        else:
            new_board[from_pos] = (count - 1, owner)

    # Add to destination
    if to_pos != "off":
        count, owner = new_board.get(to_pos, (0, None))
        if owner is not None and owner != player and count == 1:
            # Hit opponent's blot
            new_bar[1 - player] = new_bar.get(1 - player, 0) + 1
            new_board[to_pos] = (1, player)
        else:
            new_board[to_pos] = (count + 1, player)

    return new_board, new_bar

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    return {
        "board": copy.deepcopy(INITIAL_POSITION),
        "bar": {P0: 0, P1: 0},
        "borne_off": {P0: 0, P1: 0},
        "dice": [],
        "current_player": CHANCE,
        "is_terminal": False,
        "winner": None
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = {
        "board": copy.deepcopy(state["board"]),
        "bar": state["bar"].copy(),
        "borne_off": state["borne_off"].copy(),
        "dice": state["dice"].copy(),
        "current_player": state["current_player"],
        "is_terminal": False,
        "winner": None
    }

    if state["current_player"] == CHANCE:
        # Parse dice roll "D_X_Y"
        parts = action.split("_")
        d1, d2 = int(parts[1]), int(parts[2])
        if d1 == d2:
            new_state["dice"] = [d1, d1, d1, d1]
        else:
            new_state["dice"] = [d1, d2]
        # Determine first player based on higher die if initial roll
        if sum(state["borne_off"].values()) == 0 and sum(state["bar"].values()) == 0:
            # Check if this is the very first roll
            p0_count = sum(c for p, (c, o) in state["board"].items() if o == P0)
            if p0_count == 15:  # Initial position
                new_state["current_player"] = P0 if d1 >= d2 else P1
            else:
                new_state["current_player"] = P0
        else:
            # Alternate players - find who just moved
            new_state["current_player"] = P0  # Will be set properly
        return new_state

    # Parse and apply moves
    player = state["current_player"]

    if action != "pass":
        moves = action.split(",")
        for move in moves:
            parts = move.split("/")
            from_pos = parts[0]
            to_pos = parts[1]

            if from_pos == "bar":
                from_pos = "bar"
            else:
                from_pos = int(from_pos)

            if to_pos == "off":
                to_pos = "off"
                new_state["borne_off"][player] += 1
            else:
                to_pos = int(to_pos)

            new_state["board"], new_state["bar"] = _apply_single_move(
                new_state["board"], new_state["bar"], player, from_pos, to_pos
            )

    # Check for win
    if new_state["borne_off"][player] >= NUM_CHECKERS:
        new_state["is_terminal"] = True
        new_state["winner"] = player
        new_state["current_player"] = TERMINAL
    else:
        # Next player rolls
        new_state["current_player"] = CHANCE
        new_state["dice"] = []

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, with -1 for chance and -4 for terminal."""
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    names = {P0: "Player 0", P1: "Player 1", CHANCE: "Chance", TERMINAL: "Terminal"}
    return names.get(player_id, "Unknown")

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state["is_terminal"]:
        return [0.0, 0.0]

    if state["winner"] == P0:
        return [1.0, -1.0]
    else:
        return [-1.0, 1.0]

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state["is_terminal"]:
        return []

    if state["current_player"] == CHANCE:
        # All possible dice rolls
        actions = []
        for d1 in range(1, DIE_SIDES + 1):
            for d2 in range(d1, DIE_SIDES + 1):
                actions.append(f"D_{d1}_{d2}")
        return actions

    player = state["current_player"]
    return _generate_moves_for_dice(state["board"], state["bar"], player, state["dice"])

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Backgammon is perfect information."""
    obs = {
        "board": state["board"],
        "bar": state["bar"],
        "borne_off": state["borne_off"],
        "dice": state["dice"]
    }
    return [obs, obs]

import random
import itertools
from typing import Any, Dict, List, Optional, Tuple

# --- Type Definitions & Constants ---
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

SUITS = ['s', 'c', 'd', 'h']
RANKS = ['A', '2', '3', '4', '5', '6', '7', '8', '9', 'T', 'J', 'Q', 'K']
RANK_VALUES = {r: min(i + 1, 10) for i, r in enumerate(RANKS)}
RANK_INDICES = {r: i for i, r in enumerate(RANKS)}

# --- Helper Functions ---
def get_deck() -> List[str]:
    return [r + s for s in SUITS for r in RANKS]

def get_card_value(card: str) -> int:
    return RANK_VALUES[card[:-1]]

def get_deadwood_value(hand: List[str]) -> int:
    if not hand: return 0
    hand_tuple = tuple(sorted(hand, key=lambda c: (SUITS.index(c[-1]), RANK_INDICES[c[:-1]])))

    memo = {}
    def solve(curr_hand):
        if curr_hand in memo: return memo[curr_hand]
        res = sum(get_card_value(c) for c in curr_hand)

        ranks = {}
        for c in curr_hand: ranks.setdefault(c[:-1], []).append(c)
        for r, cards in ranks.items():
            if len(cards) >= 3:
                for k in range(3, len(cards) + 1):
                    for combo in itertools.combinations(cards, k):
                        rem = list(curr_hand)
                        for x in combo: rem.remove(x)
                        res = min(res, solve(tuple(rem)))

        suits = {}
        for c in curr_hand: suits.setdefault(c[-1], []).append(c)
        for s, cards in suits.items():
            cards.sort(key=lambda x: RANK_INDICES[x[:-1]])
            if len(cards) >= 3:
                for i in range(len(cards)):
                    for j in range(i + 3, len(cards) + 1):
                        sub = cards[i:j]
                        idxs = [RANK_INDICES[x[:-1]] for x in sub]
                        if all(idxs[z] + 1 == idxs[z+1] for z in range(len(idxs)-1)):
                            rem = list(curr_hand)
                            for x in sub: rem.remove(x)
                            res = min(res, solve(tuple(rem)))

        memo[curr_hand] = res
        return res
    return solve(hand_tuple)

def get_valid_melds(hand: List[str]) -> List[List[str]]:
    melds = []
    ranks = {}
    for c in hand: ranks.setdefault(c[:-1], []).append(c)
    for r in ranks:
        if len(ranks[r]) >= 3:
            for n in range(3, len(ranks[r]) + 1):
                for combo in itertools.combinations(ranks[r], n):
                    melds.append(list(combo))
    suits = {}
    for c in hand: suits.setdefault(c[-1], []).append(c)
    for s in suits:
        cards = sorted(suits[s], key=lambda c: RANK_INDICES[c[:-1]])
        if len(cards) >= 3:
            for i in range(len(cards)):
                for j in range(i + 3, len(cards) + 1):
                    sub = cards[i:j]
                    idxs = [RANK_INDICES[x[:-1]] for x in sub]
                    if all(idxs[k] + 1 == idxs[k+1] for k in range(len(idxs)-1)):
                        melds.append(sub)
    return melds

# --- Main API Functions ---

def get_initial_state() -> State:
    return {
        "deck": [],
        "hands": [[], []],
        "discard_pile": [],
        "current_player": -1, # Chance
        "phase": "init", 
        "turn_history": [],
        "scores": [0.0, 0.0],
        "dealer": 0,
        "knocker": None,
        "knock_melds": [],
        "gin": False,
        "game_over": False
    }

def get_current_player(state: State) -> int:
    if state["game_over"]: return -4
    return state["current_player"]

def get_player_name(player_id: int) -> str:
    return "Chance" if player_id == -1 else f"Player {player_id}"

def get_legal_actions(state: State) -> List[Action]:
    if state["game_over"]: return []
    cp = state["current_player"]
    phase = state["phase"]

    if cp == -1: return ["deal_random"]

    hand = state["hands"][cp]

    if phase == "first_turn":
        if len(state["turn_history"]) <= 1: 
            return ["Draw upcard", "Pass"]
        return []

    if phase == "draw":
        return ["Draw upcard", "Draw stock"]

    if phase == "discard":
        actions = [f"Action: {c}" for c in hand]
        if get_deadwood_value(hand) <= 10:
            actions.append("Action: Knock")
        return actions

    if phase == "knock":
        poss = get_valid_melds(hand)
        actions = ["Action: Done"]
        for m in poss:
            m_str = "".join(sorted(m, key=lambda c: (SUITS.index(c[-1]), RANK_INDICES[c[:-1]])))
            actions.append(f"Action: {m_str}")
        return list(set(actions))

    if phase == "layoff":
        actions = ["Action: Done"]
        for card in hand:
            actions.append(f"Action: {card}") 
        return actions

    if phase == "wall":
        return ["Action: Pass"]

    return []

def apply_action(state: State, action: Action) -> State:
    ns = {k: (v[:] if isinstance(v, list) else v) for k, v in state.items()}
    ns["hands"] = [h[:] for h in state["hands"]]

    cp = state["current_player"]
    phase = state["phase"]

    if cp == -1:
        deck = []
        if action.startswith("deal:"):
            deck = action.split(":")[1].split(",")
        else:
            deck = get_deck()
            random.shuffle(deck)

        ns["hands"][0] = deck[0:10]
        ns["hands"][1] = deck[10:20]
        ns["discard_pile"] = [deck[20]]
        ns["deck"] = deck[21:]
        ns["dealer"] = 0
        ns["current_player"] = 1 
        ns["phase"] = "first_turn"
        ns["turn_history"] = []
        return ns

    if phase == "wall":
        if action == "Action: Pass":
            ns["game_over"] = True
        return ns

    def check_wall(s):
        if len(s["deck"]) < 2:
            s["phase"] = "wall"
            s["current_player"] = 0 
            return True
        return False

    if phase == "first_turn":
        if action == "Draw upcard":
            card = ns["discard_pile"].pop()
            ns["hands"][cp].append(card)
            ns["phase"] = "discard"
        elif action == "Pass":
            ns["turn_history"].append("Pass")
            if len(ns["turn_history"]) == 1:
                ns["current_player"] = 1 - cp 
            else:
                ns["current_player"] = 1 
                card = ns["deck"].pop(0)
                ns["hands"][ns["current_player"]].append(card)
                ns["phase"] = "discard"
        return ns

    if phase == "draw":
        if action == "Draw upcard":
            ns["hands"][cp].append(ns["discard_pile"].pop())
        elif action == "Draw stock":
            if ns["deck"]:
                ns["hands"][cp].append(ns["deck"].pop(0))
        ns["phase"] = "discard"
        check_wall(ns)
        return ns

    if phase == "discard":
        if action == "Action: Knock":
            ns["phase"] = "knock"
            ns["knocker"] = cp
            if get_deadwood_value(ns["hands"][cp]) == 0: ns["gin"] = True
            return ns

        card = action.replace("Action: ", "")
        if card in ns["hands"][cp]:
            ns["hands"][cp].remove(card)
            ns["discard_pile"].append(card)
            if check_wall(ns): return ns
            ns["current_player"] = 1 - cp
            ns["phase"] = "draw"
        return ns

    if phase == "knock":
        if action == "Action: Done":
            ns["current_player"] = 1 - state["knocker"]
            if ns["gin"]: calculate_score(ns)
            else: ns["phase"] = "layoff"
        else:
            meld_str = action.replace("Action: ", "")
            cards = [meld_str[i:i+2] for i in range(0, len(meld_str), 2)]
            ns["knock_melds"].append(cards)
            for c in cards:
                if c in ns["hands"][cp]: ns["hands"][cp].remove(c)
        return ns

    if phase == "layoff":
        if action == "Action: Done":
            calculate_score(ns)
        else:
            card = action.replace("Action: ", "")
            if card in ns["hands"][cp]: ns["hands"][cp].remove(card)
        return ns

    return ns

def calculate_score(state: State):
    k, o = state["knocker"], 1 - state["knocker"]
    dw_k = sum(get_card_value(c) for c in state["hands"][k])
    dw_o = get_deadwood_value(state["hands"][o])

    if state["gin"]:
        state["scores"][k] = 25.0 + dw_o
    elif dw_k < dw_o:
        state["scores"][k] = float(dw_o - dw_k)
    else:
        state["scores"][o] = 25.0 + (dw_k - dw_o)
    state["game_over"] = True

def get_rewards(state: State) -> List[float]:
    return state["scores"] if state["game_over"] else [0.0, 0.0]

def get_observations(state: State) -> List[PlayerObservation]:
    if state["current_player"] == -1: return [{}, {}]
    obs = []
    for pid in range(2):
        obs.append({
            "hand": sorted(state["hands"][pid]),
            "discard_top": state["discard_pile"][-1] if state["discard_pile"] else None,
            "knock_melds": state["knock_melds"],
            "phase": state["phase"],
            "legal_actions": get_legal_actions(state) if state["current_player"] == pid else []
        })
    return obs

def resample_history(obs_action_history: List[Tuple[PlayerObservation, Optional[Action]]], player_id: int, last_is_terminal: bool = False) -> List[Action]:
    if not obs_action_history: return ["deal_random"]

    first_obs = obs_action_history[0][0]
    initial_hand = set(first_obs.get("hand", []))
    initial_discard = first_obs.get("discard_top")

    known_player_stock_draws = [] 
    opponent_discards = [] 

    for i in range(len(obs_action_history) - 1):
        curr_obs, action = obs_action_history[i]
        next_obs, _ = obs_action_history[i+1]

        if action == "Draw stock":
            new_cards = set(next_obs.get("hand", [])) - set(curr_obs.get("hand", []))
            if new_cards:
                card = list(new_cards)[0]
                known_player_stock_draws.append(card)
                if card in initial_hand: initial_hand.remove(card) 

        my_discard = None
        if action and action.startswith("Action: ") and action not in ["Action: Knock", "Action: Done"]:
             my_discard = action.replace("Action: ", "")

        pile_after_me = curr_obs.get("discard_top")
        if my_discard: pile_after_me = my_discard

        next_disc_top = next_obs.get("discard_top")
        if next_disc_top and next_disc_top != pile_after_me:
             opponent_discards.append(next_disc_top)

    full_deck = set(get_deck())
    used_cards = set(initial_hand)
    if initial_discard: used_cards.add(initial_discard)
    for c in known_player_stock_draws: used_cards.add(c)
    for c in opponent_discards: used_cards.add(c)

    unknowns = list(full_deck - used_cards)
    random.shuffle(unknowns)

    p_cards = list(initial_hand)
    while len(p_cards) < 10: p_cards.append(unknowns.pop())

    o_cards = list(opponent_discards) 
    while len(o_cards) < 10: o_cards.append(unknowns.pop())

    temp_stock = ["?"] * 31 
    stock_cursor = 0
    sim_p = 1 
    phase_sim = "first_turn"

    sim_p_draws = list(known_player_stock_draws)
    obs_idx = 0

    # Simulation to assign stock slots
    for _ in range(100): 
        if obs_idx >= len(obs_action_history): break
        is_me = (sim_p == player_id)

        if is_me:
            _, act = obs_action_history[obs_idx]
            obs_idx += 1

            if act == "Draw stock":
                if stock_cursor < 31:
                    if sim_p_draws:
                        temp_stock[stock_cursor] = sim_p_draws.pop(0)
                    stock_cursor += 1
                phase_sim = "discard"
            elif act == "Draw upcard":
                phase_sim = "discard"
            elif act == "Pass":
                # If first pass, stay in first_turn. If second, force draw happens logic implies valid draw.
                # Keep simplified phase tracking
                pass 
            elif act.startswith("Action: ") and act != "Action: Knock":
                 phase_sim = "draw" # After discard, back to draw

            sim_p = 1 - sim_p
        else:
            # Opponent Logic
            if phase_sim == "first_turn":
                # Opp cannot draw stock in first turn
                pass # Assume pass or upcard draw
            else:
                # Assume stock draw for standard play
                if stock_cursor < 31:
                    stock_cursor += 1
                phase_sim = "discard"
            sim_p = 1 - sim_p

    final_stock = []
    for x in temp_stock:
        if x == "?":
            final_stock.append(unknowns.pop() if unknowns else "Ah")
        elif x is not None:
             final_stock.append(x)
    final_stock = [x for x in final_stock if isinstance(x, str)]

    deck_ordered = []
    if player_id == 0:
        deck_ordered.extend(p_cards)
        deck_ordered.extend(o_cards)
    else:
        deck_ordered.extend(o_cards)
        deck_ordered.extend(p_cards)

    if initial_discard: deck_ordered.append(initial_discard)
    else: deck_ordered.append(unknowns.pop() if unknowns else "Ah")

    deck_ordered.extend(final_stock)

    actions = [f"deal:{','.join(deck_ordered)}"]
    sim_state = apply_action(get_initial_state(), actions[0])
    my_hist_iter = iter(obs_action_history)

    while not sim_state["game_over"]:
        cp = sim_state["current_player"]

        if cp == player_id:
            try:
                obs, act = next(my_hist_iter)
                actions.append(act)
                sim_state = apply_action(sim_state, act)
            except StopIteration:
                break
        else:
            if sim_state["phase"] == "first_turn":
                op_act = "Pass"
                actions.append(op_act)
                sim_state = apply_action(sim_state, op_act)
            elif sim_state["phase"] == "wall":
                op_act = "Action: Pass"
                actions.append(op_act)
                sim_state = apply_action(sim_state, op_act)
            else:
                if not sim_state["deck"]:
                    actions.append("Action: Pass") 
                    sim_state = apply_action(sim_state, "Action: Pass")
                    continue

                op_act_1 = "Draw stock"
                actions.append(op_act_1)
                sim_state = apply_action(sim_state, op_act_1)

                if opponent_discards:
                    disc = opponent_discards.pop(0)
                    if disc not in sim_state["hands"][cp]:
                        sim_state["hands"][cp].append(disc) 
                    op_act_2 = f"Action: {disc}"
                else:
                    c = sim_state["hands"][cp][0]
                    op_act_2 = f"Action: {c}"

                actions.append(op_act_2)
                sim_state = apply_action(sim_state, op_act_2)

    return actions

from typing import Any, Dict, List, Optional, Tuple
import copy

# Type Definitions
Action = str
State = Dict[str, Any]
PlayerObservation = Dict[str, Any]

# Constants
P0, P1, TERMINAL = 0, 1, -4
BOARD_SIZE = 8
FILES = 'abcdefgh'
RANKS = '12345678'

# Piece characters (uppercase=White, lowercase=Black)
WHITE_PIECES = 'KQRBNP'
BLACK_PIECES = 'kqrbnp'

def _pos_to_algebraic(r: int, c: int) -> str:
    """Convert (row, col) to algebraic notation like 'e4'."""
    return FILES[c] + RANKS[r]

def _algebraic_to_pos(sq: str) -> Tuple[int, int]:
    """Convert 'e4' to (row, col)."""
    c = FILES.index(sq[0])
    r = RANKS.index(sq[1])
    return (r, c)

def _is_white(piece: str) -> bool:
    return piece in WHITE_PIECES

def _is_black(piece: str) -> bool:
    return piece in BLACK_PIECES

def _owner(piece: str) -> Optional[int]:
    if _is_white(piece): return P0
    if _is_black(piece): return P1
    return None

def _piece_type(piece: str) -> str:
    return piece.upper()

def _in_bounds(r: int, c: int) -> bool:
    return 0 <= r < BOARD_SIZE and 0 <= c < BOARD_SIZE

def _find_king(board: List[List[str]], player: int) -> Optional[Tuple[int, int]]:
    """Find the king's position for a player."""
    king = 'K' if player == P0 else 'k'
    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            if board[r][c] == king:
                return (r, c)
    return None

def _is_attacked(board: List[List[str]], r: int, c: int, by_player: int) -> bool:
    """Check if square (r,c) is attacked by by_player."""
    for rr in range(BOARD_SIZE):
        for cc in range(BOARD_SIZE):
            piece = board[rr][cc]
            if piece == '' or _owner(piece) != by_player:
                continue
            if _can_attack(board, rr, cc, r, c):
                return True
    return False

def _can_attack(board: List[List[str]], fr: int, fc: int, tr: int, tc: int) -> bool:
    """Check if piece at (fr,fc) can attack (tr,tc)."""
    piece = board[fr][fc]
    pt = _piece_type(piece)
    dr, dc = tr - fr, tc - fc

    if pt == 'P':
        direction = 1 if _is_white(piece) else -1
        return dr == direction and abs(dc) == 1

    if pt == 'N':
        return (abs(dr), abs(dc)) in [(1, 2), (2, 1)]

    if pt == 'K':
        return abs(dr) <= 1 and abs(dc) <= 1 and (dr != 0 or dc != 0)

    if pt == 'R':
        if dr != 0 and dc != 0:
            return False
        return _path_clear(board, fr, fc, tr, tc)

    if pt == 'B':
        if abs(dr) != abs(dc) or dr == 0:
            return False
        return _path_clear(board, fr, fc, tr, tc)

    if pt == 'Q':
        if dr == 0 or dc == 0 or abs(dr) == abs(dc):
            return _path_clear(board, fr, fc, tr, tc)
        return False

    return False

def _path_clear(board: List[List[str]], fr: int, fc: int, tr: int, tc: int) -> bool:
    """Check if path between two squares is clear (exclusive of endpoints)."""
    dr = 0 if tr == fr else (1 if tr > fr else -1)
    dc = 0 if tc == fc else (1 if tc > fc else -1)

    r, c = fr + dr, fc + dc
    while (r, c) != (tr, tc):
        if board[r][c] != '':
            return False
        r, c = r + dr, c + dc
    return True

def _in_check(board: List[List[str]], player: int) -> bool:
    """Check if player's king is in check."""
    king_pos = _find_king(board, player)
    if king_pos is None:
        return True  # King captured (shouldn't happen in valid game)
    return _is_attacked(board, king_pos[0], king_pos[1], 1 - player)

def _generate_moves(state: State, only_legal: bool = True) -> List[Action]:
    """Generate all moves for current player."""
    board = state['board']
    player = state['current_player']
    moves = []

    for fr in range(BOARD_SIZE):
        for fc in range(BOARD_SIZE):
            piece = board[fr][fc]
            if piece == '' or _owner(piece) != player:
                continue

            pt = _piece_type(piece)
            piece_moves = _get_piece_moves(state, fr, fc)
            moves.extend(piece_moves)

    # Add castling
    moves.extend(_get_castling_moves(state))

    if only_legal:
        # Filter out moves that leave king in check
        legal_moves = []
        for move in moves:
            new_state = _apply_move_unchecked(state, move)
            if not _in_check(new_state['board'], player):
                legal_moves.append(move)
        return legal_moves

    return moves

def _get_piece_moves(state: State, fr: int, fc: int) -> List[Action]:
    """Get moves for piece at (fr, fc)."""
    board = state['board']
    piece = board[fr][fc]
    player = _owner(piece)
    pt = _piece_type(piece)
    moves = []

    from_sq = _pos_to_algebraic(fr, fc)

    if pt == 'P':
        direction = 1 if player == P0 else -1
        start_rank = 1 if player == P0 else 6
        promo_rank = 7 if player == P0 else 0

        # Forward one
        nr = fr + direction
        if _in_bounds(nr, fc) and board[nr][fc] == '':
            if nr == promo_rank:
                for promo in 'QRBN':
                    moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, fc)}_{promo}")
            else:
                moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, fc)}")

            # Forward two from start
            if fr == start_rank:
                nr2 = fr + 2 * direction
                if board[nr2][fc] == '':
                    moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr2, fc)}")

        # Captures
        for dc in [-1, 1]:
            nr, nc = fr + direction, fc + dc
            if not _in_bounds(nr, nc):
                continue

            target = board[nr][nc]
            # Regular capture or en passant
            ep = state.get('en_passant')
            if (target != '' and _owner(target) != player) or (ep and ep == (nr, nc)):
                if nr == promo_rank:
                    for promo in 'QRBN':
                        moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, nc)}_{promo}")
                else:
                    moves.append(f"P_{from_sq}_{_pos_to_algebraic(nr, nc)}")

    elif pt == 'N':
        for dr, dc in [(-2, -1), (-2, 1), (-1, -2), (-1, 2),
                       (1, -2), (1, 2), (2, -1), (2, 1)]:
            nr, nc = fr + dr, fc + dc
            if _in_bounds(nr, nc):
                target = board[nr][nc]
                if target == '' or _owner(target) != player:
                    moves.append(f"N_{from_sq}_{_pos_to_algebraic(nr, nc)}")

    elif pt == 'K':
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                if dr == 0 and dc == 0:
                    continue
                nr, nc = fr + dr, fc + dc
                if _in_bounds(nr, nc):
                    target = board[nr][nc]
                    if target == '' or _owner(target) != player:
                        moves.append(f"K_{from_sq}_{_pos_to_algebraic(nr, nc)}")

    elif pt in 'RBQ':
        directions = []
        if pt in 'RQ':
            directions.extend([(0, 1), (0, -1), (1, 0), (-1, 0)])
        if pt in 'BQ':
            directions.extend([(1, 1), (1, -1), (-1, 1), (-1, -1)])

        for dr, dc in directions:
            nr, nc = fr + dr, fc + dc
            while _in_bounds(nr, nc):
                target = board[nr][nc]
                if target == '':
                    moves.append(f"{pt}_{from_sq}_{_pos_to_algebraic(nr, nc)}")
                elif _owner(target) != player:
                    moves.append(f"{pt}_{from_sq}_{_pos_to_algebraic(nr, nc)}")
                    break
                else:
                    break
                nr, nc = nr + dr, nc + dc

    return moves

def _get_castling_moves(state: State) -> List[Action]:
    """Get castling moves if legal."""
    moves = []
    board = state['board']
    player = state['current_player']
    rights = state['castling_rights']

    rank = 0 if player == P0 else 7
    king_file = 4

    # Check king hasn't moved and not in check
    if _in_check(board, player):
        return moves

    # Kingside
    if rights[player]['kingside']:
        if (board[rank][5] == '' and board[rank][6] == '' and
            not _is_attacked(board, rank, 5, 1 - player) and
            not _is_attacked(board, rank, 6, 1 - player)):
            moves.append('O-O')

    # Queenside
    if rights[player]['queenside']:
        if (board[rank][1] == '' and board[rank][2] == '' and board[rank][3] == '' and
            not _is_attacked(board, rank, 2, 1 - player) and
            not _is_attacked(board, rank, 3, 1 - player)):
            moves.append('O-O-O')

    return moves

def _apply_move_unchecked(state: State, action: Action) -> State:
    """Apply move without checking legality."""
    new_board = [row[:] for row in state['board']]
    player = state['current_player']
    new_rights = copy.deepcopy(state['castling_rights'])
    new_ep = None
    new_halfmove = state['halfmove_clock'] + 1

    if action == 'O-O':
        rank = 0 if player == P0 else 7
        king = 'K' if player == P0 else 'k'
        rook = 'R' if player == P0 else 'r'
        new_board[rank][4] = ''
        new_board[rank][7] = ''
        new_board[rank][6] = king
        new_board[rank][5] = rook
        new_rights[player] = {'kingside': False, 'queenside': False}
        new_halfmove = state['halfmove_clock'] + 1

    elif action == 'O-O-O':
        rank = 0 if player == P0 else 7
        king = 'K' if player == P0 else 'k'
        rook = 'R' if player == P0 else 'r'
        new_board[rank][4] = ''
        new_board[rank][0] = ''
        new_board[rank][2] = king
        new_board[rank][3] = rook
        new_rights[player] = {'kingside': False, 'queenside': False}

    else:
        parts = action.split('_')
        piece_char = parts[0]
        from_sq = parts[1]
        to_sq = parts[2]
        promo = parts[3] if len(parts) > 3 else None

        fr, fc = _algebraic_to_pos(from_sq)
        tr, tc = _algebraic_to_pos(to_sq)

        piece = new_board[fr][fc]
        captured = new_board[tr][tc]

        # Handle en passant capture
        if piece_char == 'P' and state.get('en_passant') == (tr, tc):
            ep_capture_r = fr  # Pawn being captured is on same rank as moving pawn
            new_board[ep_capture_r][tc] = ''
            new_halfmove = 0

        new_board[fr][fc] = ''

        # Promotion
        if promo:
            piece = promo if player == P0 else promo.lower()
            new_halfmove = 0

        new_board[tr][tc] = piece

        # Reset halfmove on pawn move or capture
        if piece_char == 'P' or captured != '':
            new_halfmove = 0

        # Set en passant square
        if piece_char == 'P' and abs(tr - fr) == 2:
            new_ep = ((fr + tr) // 2, fc)

        # Update castling rights
        if piece_char == 'K':
            new_rights[player] = {'kingside': False, 'queenside': False}
        if piece_char == 'R':
            if fc == 0:
                new_rights[player]['queenside'] = False
            elif fc == 7:
                new_rights[player]['kingside'] = False

        # If rook captured
        if captured != '' and _piece_type(captured) == 'R':
            opp = 1 - player
            if tr == (0 if opp == P0 else 7):
                if tc == 0:
                    new_rights[opp]['queenside'] = False
                elif tc == 7:
                    new_rights[opp]['kingside'] = False

    return {
        'board': new_board,
        'current_player': 1 - player,
        'castling_rights': new_rights,
        'en_passant': new_ep,
        'halfmove_clock': new_halfmove,
        'is_terminal': False,
        'result': None
    }

def _insufficient_material(board: List[List[str]]) -> bool:
    """Check for insufficient material draw."""
    pieces = []
    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            p = board[r][c]
            if p != '':
                pieces.append(p.upper())

    pieces.sort()

    # K vs K
    if pieces == ['K', 'K']:
        return True
    # K+B vs K or K+N vs K
    if pieces in [['B', 'K', 'K'], ['K', 'K', 'N']]:
        return True

    return False

def get_initial_state() -> State:
    """Returns the initial game state before any actions are taken."""
    board = [['' for _ in range(BOARD_SIZE)] for _ in range(BOARD_SIZE)]

    # Set up initial position
    back_rank_white = ['R', 'N', 'B', 'Q', 'K', 'B', 'N', 'R']
    back_rank_black = ['r', 'n', 'b', 'q', 'k', 'b', 'n', 'r']

    board[0] = back_rank_white[:]
    board[1] = ['P'] * 8
    board[6] = ['p'] * 8
    board[7] = back_rank_black[:]

    return {
        'board': board,
        'current_player': P0,
        'castling_rights': {
            P0: {'kingside': True, 'queenside': True},
            P1: {'kingside': True, 'queenside': True}
        },
        'en_passant': None,
        'halfmove_clock': 0,
        'is_terminal': False,
        'result': None  # 'white', 'black', 'draw'
    }

def apply_action(state: State, action: Action) -> State:
    """Returns the new state after an action has been taken."""
    new_state = _apply_move_unchecked(state, action)

    # Check for game end
    opponent = new_state['current_player']
    legal_moves = _generate_moves(new_state, only_legal=True)

    if len(legal_moves) == 0:
        new_state['is_terminal'] = True
        new_state['current_player'] = TERMINAL
        if _in_check(new_state['board'], opponent):
            # Checkmate
            new_state['result'] = 'white' if opponent == P1 else 'black'
        else:
            # Stalemate
            new_state['result'] = 'draw'
    elif new_state['halfmove_clock'] >= 50:  # 25-move rule (stricter for training)
        new_state['is_terminal'] = True
        new_state['current_player'] = TERMINAL
        new_state['result'] = 'draw'
    elif _insufficient_material(new_state['board']):
        new_state['is_terminal'] = True
        new_state['current_player'] = TERMINAL
        new_state['result'] = 'draw'

    return new_state

def get_current_player(state: State) -> int:
    """Returns current player, or -4 for terminal state."""
    return state['current_player']

def get_player_name(player_id: int) -> str:
    """Returns the name of the player."""
    if player_id == P0: return "Player 0 (White)"
    if player_id == P1: return "Player 1 (Black)"
    return "Terminal"

def get_rewards(state: State) -> List[float]:
    """Returns the rewards per player. Non-zero only at terminal states."""
    if not state['is_terminal']:
        return [0.0, 0.0]

    result = state['result']
    if result == 'white':
        return [1.0, -1.0]
    elif result == 'black':
        return [-1.0, 1.0]
    else:
        return [0.0, 0.0]  # Draw

def get_legal_actions(state: State) -> List[Action]:
    """Returns legal actions for current state. Empty list if terminal."""
    if state['is_terminal']:
        return []
    return _generate_moves(state, only_legal=True)

def get_observations(state: State) -> List[PlayerObservation]:
    """Returns [player_0_obs, player_1_obs]. Chess is perfect information."""
    obs = {
        'board': state['board'],
        'castling_rights': state['castling_rights'],
        'en_passant': state['en_passant'],
        'halfmove_clock': state['halfmove_clock']
    }
    return [obs, obs]
